def login_redirect(login_url, next_url=None, default_url="/"):
    from urllib.parse import urlencode, urlparse, urlunparse, parse_qsl

    def is_safe_url(target):
        if not target:
            return False
        parsed = urlparse(target)
        return parsed.scheme in ("", "http", "https") and parsed.netloc in ("", urlparse(login_url).netloc)

    destination = next_url if is_safe_url(next_url) else default_url

    parsed_login = urlparse(login_url)
    query = dict(parse_qsl(parsed_login.query))
    if destination and destination != default_url:
        query["next"] = destination

    return urlunparse(
        (
            parsed_login.scheme,
            parsed_login.netloc,
            parsed_login.path,
            parsed_login.params,
            urlencode(query, doseq=True),
            parsed_login.fragment,
        )
    )